// fetch-based HTTP helpers (replaces axios to avoid task runner crash)
async function _post(url, data, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'POST', headers: headers, body: JSON.stringify(data), signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _get(url, opts) {
  var qurl = url;
  if (opts && opts.params) { var qs = new URLSearchParams(opts.params).toString(); if (qs) qurl += (url.includes('?') ? '&' : '?') + qs; }
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(qurl, {headers: headers, signal: opts && opts.timeout ? AbortSignal.timeout(opts.timeout) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _del(url, opts) {
  var headers = {'Content-Type': 'application/json'};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'DELETE', headers: headers, body: opts && opts.data ? JSON.stringify(opts.data) : undefined});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  if (!r.ok) { var err = new Error('HTTP ' + r.status); err.response = {status: r.status, data: json}; throw err; }
  return {data: json, status: r.status};
}
async function _put(url, body, opts) {
  var headers = {};
  if (opts && opts.headers) Object.assign(headers, opts.headers);
  var r = await fetch(url, {method:'PUT', headers: headers, body: typeof body === 'string' ? body : JSON.stringify(body)});
  var text = await r.text();
  var json; try { json = JSON.parse(text); } catch(e) { json = text; }
  return {data: json, status: r.status};
}
const M = 'http://mlflow:5050/api/2.0/mlflow';
const body = $input.item.json.body;
const action = body.action;

try {

if (!action) throw new Error('action required: log, get, search, summary, feedback, feedback_search, export_corrections, promote, baseline_set, baseline_get, drift_check');

async function post(path, data) {
  var r = await fetch(M + path, {method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(data)});
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

async function apiGet(path) {
  var r = await fetch(M + path);
  if (!r.ok) throw new Error('MLflow ' + r.status + ': ' + (await r.text()));
  return r.json();
}

// Helper: get or create experiment by name
async function getOrCreateExperiment(name) {
  try {
    var res = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent(name));
    return res.experiment.experiment_id;
  } catch(e) {
    var cr = await post('/experiments/create', {name: name});
    return cr.experiment_id;
  }
}

// Helper: find run by tag
async function findRunByTag(expId, tagKey, tagValue) {
  var filter = "tags.`" + tagKey + "` = '" + tagValue.replace(/'/g, "\\'") + "'";
  var res = await post('/runs/search', {
    experiment_ids: [expId],
    filter: filter,
    max_results: 1
  });
  return (res.runs && res.runs.length > 0) ? res.runs[0] : null;
}

// ── LOG ──────────────────────────────────────────────────────────────────
if (action === 'log') {
  var traceId = body.trace_id;
  if (!traceId) throw new Error('trace_id required');
  var source = body.source || 'unknown';
  var expId = await getOrCreateExperiment('__traces');
  var startTime = Date.now();
  var runRes = await post('/runs/create', {
    experiment_id: expId,
    start_time: startTime,
    run_name: traceId
  });
  var runId = runRes.run.info.run_id;

  var params = [
    {key: 'trace_id', value: traceId},
    {key: 'source', value: source},
    {key: 'model', value: body.model || ''},
    {key: 'status', value: body.status || 'ok'}
  ];
  if (body.prompt_name) params.push({key: 'prompt_name', value: body.prompt_name});
  if (body.prompt_version) params.push({key: 'prompt_version', value: String(body.prompt_version)});
  if (body.input) params.push({key: 'input', value: String(body.input).substring(0, 5000)});
  if (body.output) params.push({key: 'output', value: String(body.output).substring(0, 5000)});

  var metrics = [];
  if (body.latency_ms != null) metrics.push({key: 'latency_ms', value: Number(body.latency_ms), timestamp: startTime, step: 0});
  var tokens = body.tokens || {};
  if (tokens.prompt != null) metrics.push({key: 'prompt_tokens', value: Number(tokens.prompt), timestamp: startTime, step: 0});
  if (tokens.completion != null) metrics.push({key: 'completion_tokens', value: Number(tokens.completion), timestamp: startTime, step: 0});
  if (tokens.total != null) metrics.push({key: 'total_tokens', value: Number(tokens.total), timestamp: startTime, step: 0});
  if (body.tool_call_count != null) metrics.push({key: 'tool_call_count', value: Number(body.tool_call_count), timestamp: startTime, step: 0});

  var tags = [{key: 'trace_id', value: traceId}];
  if (body.metadata) tags.push({key: 'mlflow.note.content', value: JSON.stringify(body.metadata).substring(0, 5000)});

  await post('/runs/log-batch', {run_id: runId, params: params, metrics: metrics, tags: tags});
  await post('/runs/update', {run_id: runId, status: 'FINISHED', end_time: Date.now()});
  return {action: 'log', trace_id: traceId, run_id: runId, source: source};
}

// ── GET ──────────────────────────────────────────────────────────────────
if (action === 'get') {
  var traceId = body.trace_id;
  if (!traceId) throw new Error('trace_id required');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    throw new Error('No traces found (experiment does not exist)');
  }
  var run = await findRunByTag(expId, 'trace_id', traceId);
  if (!run) { return {error: true, message: 'Trace not found: ' + traceId, _status: 404}; }
  var info = run.info || {};
  var params = {};
  (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
  var metrics = {};
  (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
  var tags = {};
  (run.data && run.data.tags || []).forEach(function(t) { tags[t.key] = t.value; });
  return {
    action: 'get',
    trace_id: traceId,
    run_id: info.run_id,
    source: params.source || '',
    model: params.model || '',
    prompt_name: params.prompt_name || null,
    prompt_version: params.prompt_version || null,
    status: params.status || '',
    latency_ms: metrics.latency_ms || null,
    tokens: {
      prompt: metrics.prompt_tokens || null,
      completion: metrics.completion_tokens || null,
      total: metrics.total_tokens || null
    },
    tool_call_count: metrics.tool_call_count || null,
    feedback_rating: metrics.feedback_rating || null,
    feedback_correction: tags.feedback_correction || null,
    created_at: Number(info.start_time)
  };
}

// ── SEARCH ───────────────────────────────────────────────────────────────
if (action === 'search') {
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'search', traces: [], count: 0};
  }
  var limit = body.limit || 25;
  var filters = [];
  function esc(v) { return String(v).replace(/'/g, "\\'"  ); }
  if (body.source) filters.push("params.source = '" + esc(body.source) + "'");
  if (body.prompt_name) filters.push("params.prompt_name = '" + esc(body.prompt_name) + "'");
  if (body.status) filters.push("params.status = '" + esc(body.status) + "'");
  if (body.model) filters.push("params.model = '" + esc(body.model) + "'");
  var searchBody = {
    experiment_ids: [expId],
    max_results: limit,
    order_by: ['start_time DESC']
  };
  if (filters.length > 0) searchBody.filter = filters.join(' AND ');
  var searchRes = await post('/runs/search', searchBody);
  var traces = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    return {
      trace_id: params.trace_id || info.run_name || '',
      run_id: info.run_id,
      source: params.source || '',
      model: params.model || '',
      prompt_name: params.prompt_name || null,
      status: params.status || '',
      latency_ms: metrics.latency_ms || null,
      total_tokens: metrics.total_tokens || null,
      feedback_rating: metrics.feedback_rating || null,
      created_at: Number(info.start_time)
    };
  });
  return {action: 'search', traces: traces, count: traces.length};
}

// ── SUMMARY ──────────────────────────────────────────────────────────────
if (action === 'summary') {
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'summary', total_calls: 0, avg_latency_ms: 0, total_tokens: 0, by_source: {}};
  }
  var searchBody = {
    experiment_ids: [expId],
    max_results: body.limit || 1000,
    order_by: ['start_time DESC']
  };
  // Time filter: since = ISO date or hours integer
  if (body.since) {
    var sinceTs;
    if (typeof body.since === 'number') {
      sinceTs = Date.now() - (body.since * 3600000);
    } else {
      sinceTs = new Date(body.since).getTime();
    }
    searchBody.filter = "attributes.start_time > " + sinceTs;
  }
  var searchRes = await post('/runs/search', searchBody);
  var runs = searchRes.runs || [];
  var totalLatency = 0;
  var totalTokens = 0;
  var latencyCount = 0;
  var bySource = {};
  var errorCount = 0;
  runs.forEach(function(run) {
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    var src = params.source || 'unknown';
    if (!bySource[src]) bySource[src] = {count: 0, total_latency_ms: 0, total_tokens: 0, errors: 0};
    bySource[src].count++;
    if (metrics.latency_ms != null) { totalLatency += metrics.latency_ms; bySource[src].total_latency_ms += metrics.latency_ms; latencyCount++; }
    if (metrics.total_tokens != null) { totalTokens += metrics.total_tokens; bySource[src].total_tokens += metrics.total_tokens; }
    if (params.status === 'error') { errorCount++; bySource[src].errors++; }
  });
  // Compute averages per source
  Object.keys(bySource).forEach(function(src) {
    var s = bySource[src];
    s.avg_latency_ms = s.count > 0 ? Math.round(s.total_latency_ms / s.count) : 0;
    delete s.total_latency_ms;
  });
  return {
    action: 'summary',
    total_calls: runs.length,
    avg_latency_ms: latencyCount > 0 ? Math.round(totalLatency / latencyCount) : 0,
    total_tokens: totalTokens,
    error_count: errorCount,
    error_rate: runs.length > 0 ? Math.round((errorCount / runs.length) * 1000) / 1000 : 0,
    by_source: bySource
  };
}

// ── FEEDBACK ─────────────────────────────────────────────────────────────
if (action === 'feedback') {
  var traceId = body.trace_id;
  var rating = body.rating;
  if (!traceId) throw new Error('trace_id required');
  if (rating == null || rating < 1 || rating > 5) throw new Error('rating required (1-5)');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    throw new Error('No traces found');
  }
  var run = await findRunByTag(expId, 'trace_id', traceId);
  if (!run) { return {error: true, message: 'Trace not found: ' + traceId, _status: 404}; }
  var runId = run.info.run_id;
  var ts = Date.now();
  var batchReq = {
    run_id: runId,
    metrics: [{key: 'feedback_rating', value: Number(rating), timestamp: ts, step: 0}],
    tags: []
  };
  if (body.correction) batchReq.tags.push({key: 'feedback_correction', value: String(body.correction).substring(0, 5000)});
  if (body.annotator) batchReq.tags.push({key: 'feedback_annotator', value: String(body.annotator)});
  if (body.tags && Array.isArray(body.tags)) batchReq.tags.push({key: 'feedback_tags', value: body.tags.join(',')});
  batchReq.metrics.push({key: 'has_correction', value: body.correction ? 1 : 0, timestamp: ts, step: 0});
  await post('/runs/log-batch', batchReq);
  // Auto-promote if rating >= 4 or correction exists
  var shouldPromote = (rating >= 4 || body.correction) && body.auto_promote !== false;
  var promoted = null;
  if (shouldPromote) {
    try {
      var N8N_SELF = $env.N8N_INTERNAL_URL || 'http://n8n:5678/webhook';
      var promoteResp = await _post(N8N_SELF + '/traces', {
        action: 'promote',
        trace_id: traceId,
        task: body.task || 'general',
        tags: body.tags || ['auto-promoted', 'rating-' + rating]
      }, {timeout: 60000, headers: {'X-API-Key': $env.WEBHOOK_API_KEY || ''}});
      promoted = promoteResp.data;
    } catch(promoteErr) {
      promoted = {error: true, message: promoteErr.message || String(promoteErr)};
    }
  }
  return {action: 'feedback', trace_id: traceId, run_id: runId, rating: rating, status: 'recorded', promoted: promoted};
}

// ── FEEDBACK_SEARCH ──────────────────────────────────────────────────────
if (action === 'feedback_search') {
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'feedback_search', traces: [], count: 0};
  }
  var filters = ['metrics.feedback_rating > 0'];
  if (body.rating_min) filters.push('metrics.feedback_rating >= ' + Number(body.rating_min));
  if (body.rating_max) filters.push('metrics.feedback_rating <= ' + Number(body.rating_max));
  if (body.has_correction) filters.push('metrics.has_correction = 1');
  var searchRes = await post('/runs/search', {
    experiment_ids: [expId],
    filter: filters.join(' AND '),
    max_results: body.limit || 25,
    order_by: ['start_time DESC']
  });
  var traces = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    var tags = {};
    (run.data && run.data.tags || []).forEach(function(t) { tags[t.key] = t.value; });
    return {
      trace_id: params.trace_id || '',
      run_id: info.run_id,
      source: params.source || '',
      model: params.model || '',
      prompt_name: params.prompt_name || null,
      rating: metrics.feedback_rating || null,
      correction: tags.feedback_correction || null,
      annotator: tags.feedback_annotator || null
    };
  });
  return {action: 'feedback_search', traces: traces, count: traces.length};
}

// ── EXPORT_CORRECTIONS ───────────────────────────────────────────────────
if (action === 'export_corrections') {
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'export_corrections', corrections: [], count: 0};
  }
  var searchRes = await post('/runs/search', {
    experiment_ids: [expId],
    filter: 'metrics.has_correction = 1',
    max_results: body.limit || 100,
    order_by: ['start_time DESC']
  });
  var corrections = (searchRes.runs || []).map(function(run) {
    var info = run.info || {};
    var params = {};
    (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
    var tags = {};
    (run.data && run.data.tags || []).forEach(function(t) { tags[t.key] = t.value; });
    var metrics = {};
    (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
    return {
      trace_id: params.trace_id || '',
      source: params.source || '',
      prompt_name: params.prompt_name || null,
      model: params.model || '',
      correction: tags.feedback_correction || '',
      rating: metrics.feedback_rating || null,
      annotator: tags.feedback_annotator || null,
      created_at: Number(info.start_time)
    };
  });
  return {action: 'export_corrections', corrections: corrections, count: corrections.length};
}


// ── BASELINE_SET_BENCHMARK ──────────────────────────────────────────────────
if (action === 'baseline_set_benchmark') {
  var promptName = body.prompt_name;
  if (!promptName) throw new Error('prompt_name required');
  var scores = body.scores || {};
  var passRate = body.pass_rate;
  var casesEvaluated = body.cases_evaluated;
  var version = body.version || '';

  var expId = await getOrCreateExperiment('__baselines');
  // End existing baseline if found
  var existing = await findRunByTag(expId, 'prompt_name', promptName);
  if (existing && existing.info.status === 'RUNNING') {
    await post('/runs/update', {run_id: existing.info.run_id, status: 'FINISHED', end_time: Date.now()});
  }

  var ts = Date.now();
  var runRes = await post('/runs/create', {
    experiment_id: expId,
    start_time: ts,
    run_name: 'baseline-benchmark-' + promptName
  });
  var runId = runRes.run.info.run_id;

  var batchMetrics = [];
  // Store individual score metrics
  var scoreKeys = Object.keys(scores);
  for (var si = 0; si < scoreKeys.length; si++) {
    batchMetrics.push({key: 'score_' + scoreKeys[si], value: Number(scores[scoreKeys[si]]), timestamp: ts, step: 0});
  }
  if (passRate != null) batchMetrics.push({key: 'pass_rate', value: Number(passRate), timestamp: ts, step: 0});
  if (casesEvaluated != null) batchMetrics.push({key: 'cases_evaluated', value: Number(casesEvaluated), timestamp: ts, step: 0});
  if (body.latency_p50_ms != null) batchMetrics.push({key: 'latency_p50_ms', value: Number(body.latency_p50_ms), timestamp: ts, step: 0});
  if (body.latency_p95_ms != null) batchMetrics.push({key: 'latency_p95_ms', value: Number(body.latency_p95_ms), timestamp: ts, step: 0});

  var batchTags = [
    {key: 'prompt_name', value: promptName},
    {key: 'baseline_type', value: 'benchmark'}
  ];
  if (version) batchTags.push({key: 'prompt_version', value: String(version)});

  await post('/runs/log-batch', {
    run_id: runId,
    params: [{key: 'prompt_name', value: promptName}],
    metrics: batchMetrics,
    tags: batchTags
  });
  await post('/runs/update', {run_id: runId, status: 'FINISHED', end_time: Date.now()});
  return {action: 'baseline_set_benchmark', prompt_name: promptName, run_id: runId, scores: scores, pass_rate: passRate, status: 'baseline_set'};
}

// ── BASELINE_SET ─────────────────────────────────────────────────────────
if (action === 'baseline_set') {
  var promptName = body.prompt_name;
  var metricsObj = body.metrics;
  if (!promptName) throw new Error('prompt_name required');
  if (!metricsObj) throw new Error('metrics object required (avg_latency_ms, avg_tokens, error_rate)');
  var expId = await getOrCreateExperiment('__baselines');
  // Check for existing baseline — end it if found
  var existing = await findRunByTag(expId, 'prompt_name', promptName);
  if (existing && existing.info.status === 'RUNNING') {
    await post('/runs/update', {run_id: existing.info.run_id, status: 'FINISHED', end_time: Date.now()});
  }
  var ts = Date.now();
  var runRes = await post('/runs/create', {
    experiment_id: expId,
    start_time: ts,
    run_name: 'baseline-' + promptName
  });
  var runId = runRes.run.info.run_id;
  var batchMetrics = [];
  if (metricsObj.avg_latency_ms != null) batchMetrics.push({key: 'avg_latency_ms', value: Number(metricsObj.avg_latency_ms), timestamp: ts, step: 0});
  if (metricsObj.avg_tokens != null) batchMetrics.push({key: 'avg_tokens', value: Number(metricsObj.avg_tokens), timestamp: ts, step: 0});
  if (metricsObj.error_rate != null) batchMetrics.push({key: 'error_rate', value: Number(metricsObj.error_rate), timestamp: ts, step: 0});
  await post('/runs/log-batch', {
    run_id: runId,
    params: [{key: 'prompt_name', value: promptName}],
    metrics: batchMetrics,
    tags: [{key: 'prompt_name', value: promptName}]
  });
  await post('/runs/update', {run_id: runId, status: 'FINISHED', end_time: Date.now()});
  return {action: 'baseline_set', prompt_name: promptName, run_id: runId, metrics: metricsObj, status: 'baseline_set'};
}

// ── BASELINE_GET ─────────────────────────────────────────────────────────
if (action === 'baseline_get') {
  var promptName = body.prompt_name;
  if (!promptName) throw new Error('prompt_name required');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__baselines'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    return {error: true, message: 'No baselines found', _status: 404};
  }
  // Find most recent baseline for this prompt
  var safePN = String(promptName).replace(/'/g, "\\'" );
  var searchRes = await post('/runs/search', {
    experiment_ids: [expId],
    filter: "tags.`prompt_name` = '" + safePN + "'",
    max_results: 1,
    order_by: ['start_time DESC']
  });
  var runs = searchRes.runs || [];
  if (runs.length === 0) return {error: true, message: 'No baseline for: ' + promptName, _status: 404};
  var run = runs[0];
  var metrics = {};
  (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
  return {
    action: 'baseline_get',
    prompt_name: promptName,
    run_id: run.info.run_id,
    metrics: metrics,
    created_at: Number(run.info.start_time)
  };
}

// ── DRIFT_CHECK ──────────────────────────────────────────────────────────
if (action === 'drift_check') {
  var promptName = body.prompt_name;
  if (!promptName) throw new Error('prompt_name required');
  var windowHours = body.window_hours || 24;
  // Get baseline
  var baselineExpId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__baselines'));
    baselineExpId = expRes.experiment.experiment_id;
  } catch(e) {
    return {error: true, message: 'No baselines found — set a baseline first', _status: 404};
  }
  var safeDriftPN = String(promptName).replace(/'/g, "\\'" );
  var baseRes = await post('/runs/search', {
    experiment_ids: [baselineExpId],
    filter: "tags.`prompt_name` = '" + safeDriftPN + "'",
    max_results: 1,
    order_by: ['start_time DESC']
  });
  if (!baseRes.runs || baseRes.runs.length === 0) return {error: true, message: 'No baseline for: ' + promptName, _status: 404};
  var baseMetrics = {};
  (baseRes.runs[0].data && baseRes.runs[0].data.metrics || []).forEach(function(m) { baseMetrics[m.key] = m.value; });

  // Get recent traces for this prompt
  var traceExpId;
  try {
    var traceRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    traceExpId = traceRes.experiment.experiment_id;
  } catch(e) {
    return {action: 'drift_check', prompt_name: promptName, drifted: false, reason: 'no traces yet', current: {}, baseline: baseMetrics};
  }
  var sinceTs = Date.now() - (windowHours * 3600000);
  var traceSearch = await post('/runs/search', {
    experiment_ids: [traceExpId],
    filter: "params.prompt_name = '" + safeDriftPN + "' AND attributes.start_time > " + sinceTs,
    max_results: 500
  });
  var traces = traceSearch.runs || [];
  if (traces.length === 0) return {action: 'drift_check', prompt_name: promptName, drifted: false, reason: 'no recent traces', current: {}, baseline: baseMetrics, window_hours: windowHours};

  var totalLat = 0, latCount = 0, totalTok = 0, errorCount = 0;
  traces.forEach(function(run) {
    var m = {};
    (run.data && run.data.metrics || []).forEach(function(met) { m[met.key] = met.value; });
    var p = {};
    (run.data && run.data.params || []).forEach(function(par) { p[par.key] = par.value; });
    if (m.latency_ms != null) { totalLat += m.latency_ms; latCount++; }
    if (m.total_tokens != null) totalTok += m.total_tokens;
    if (p.status === 'error') errorCount++;
  });
  var currentMetrics = {
    avg_latency_ms: latCount > 0 ? Math.round(totalLat / latCount) : 0,
    avg_tokens: traces.length > 0 ? Math.round(totalTok / traces.length) : 0,
    error_rate: traces.length > 0 ? Math.round((errorCount / traces.length) * 1000) / 1000 : 0,
    sample_size: traces.length
  };

  // Compare against baseline thresholds (drift = >20% degradation)
  var drifted = false;
  var reasons = [];
  if (baseMetrics.avg_latency_ms && currentMetrics.avg_latency_ms > baseMetrics.avg_latency_ms * 1.2) {
    drifted = true;
    reasons.push('latency +' + Math.round(((currentMetrics.avg_latency_ms / baseMetrics.avg_latency_ms) - 1) * 100) + '%');
  }
  if (baseMetrics.error_rate != null && currentMetrics.error_rate > baseMetrics.error_rate * 1.5) {
    drifted = true;
    reasons.push('error_rate +' + Math.round(((currentMetrics.error_rate / (baseMetrics.error_rate || 0.001)) - 1) * 100) + '%');
  }
  return {
    action: 'drift_check',
    prompt_name: promptName,
    drifted: drifted,
    reasons: reasons,
    current: currentMetrics,
    baseline: baseMetrics,
    window_hours: windowHours
  };
}

// ── HEALTH ─────────────────────────────────────────────────────────────────
if (action === 'health') {
  var traceExp = null;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    traceExp = expRes.experiment;
  } catch(e) {}
  var recentCount = 0;
  if (traceExp) {
    var since1h = Date.now() - 3600000;
    var recent = await post('/runs/search', {
      experiment_ids: [traceExp.experiment_id],
      filter: 'attributes.start_time > ' + since1h,
      max_results: 1000
    });
    recentCount = (recent.runs || []).length;
  }
  return {
    action: 'health',
    status: 'ok',
    traces_experiment: traceExp ? {id: traceExp.experiment_id, name: traceExp.name} : null,
    traces_last_hour: recentCount,
    timestamp: Date.now()
  };
}

// ── PROMOTE ────────────────────────────────────────────────────────────────
if (action === 'promote') {
  var traceId = body.trace_id;
  if (!traceId) throw new Error('trace_id required');
  var expId;
  try {
    var expRes = await apiGet('/experiments/get-by-name?experiment_name=' + encodeURIComponent('__traces'));
    expId = expRes.experiment.experiment_id;
  } catch(e) {
    throw new Error('No traces found');
  }
  var run = await findRunByTag(expId, 'trace_id', traceId);
  if (!run) return {error: true, message: 'Trace not found: ' + traceId, _status: 404};
  var params = {};
  (run.data && run.data.params || []).forEach(function(p) { params[p.key] = p.value; });
  var metrics = {};
  (run.data && run.data.metrics || []).forEach(function(m) { metrics[m.key] = m.value; });
  var tags = {};
  (run.data && run.data.tags || []).forEach(function(t) { tags[t.key] = t.value; });
  if (!params.input) return {error: true, message: 'Trace has no input stored (logged before input/output support)', _status: 400};
  var input = params.input;
  var traceOutput = params.output || '';
  var correction = tags.feedback_correction || '';
  var expected = correction || traceOutput;
  if (!expected) return {error: true, message: 'No output or correction available for promotion', _status: 400};
  // Determine domain and task from prompt_name (e.g. 'coder.SYSTEM' -> domain='coder')
  var promptName = params.prompt_name || params.source || 'unknown';
  var domain = promptName.split('.')[0];
  var taskName = body.task || 'general';
  // Generate criteria via LLM
  var criteria = body.criteria || '';
  if (!criteria) {
    var INFERENCE_BASE = $env.INFERENCE_BASE_URL || 'http://litellm:4000/v1';
    var INFERENCE_KEY = $env.LITELLM_API_KEY || '';
    var criteriaModel = $env.INFERENCE_DEFAULT_MODEL || 'qwen2.5:14b';
    try {
      var llmHeaders = INFERENCE_KEY ? {'Authorization': 'Bearer ' + INFERENCE_KEY} : {};
      var criteriaResp = await _post(INFERENCE_BASE + '/chat/completions', {
        model: criteriaModel,
        messages: [
          {role: 'system', content: 'Generate a concise evaluation criteria sentence for judging an LLM response. The criteria should describe what a good response must include. Reply with ONLY the criteria text, no explanation. Keep it under 100 words.'},
          {role: 'user', content: 'Input: ' + input.substring(0, 1000) + '\n\nExpected output: ' + expected.substring(0, 1000)}
        ],
        temperature: 0.1,
        max_tokens: 200
      }, {timeout: 30000, headers: llmHeaders});
      criteria = criteriaResp.data.choices[0].message.content.trim();
    } catch(llmErr) {
      criteria = 'Response should address the input accurately and completely.';
    }
  }
  // Build benchmark case
  var benchmarkCase = {
    input: input,
    expected: expected,
    criteria: criteria,
    domain: domain,
    task: taskName,
    tags: body.tags || ['auto-promoted']
  };
  // Push to MLflow dataset via mlflow-data-v1
  var N8N_BASE = $env.N8N_INTERNAL_URL || 'http://n8n:5678/webhook';
  var datasetName = domain + '.' + taskName;
  try {
    await _post(N8N_BASE + '/datasets', {
      action: 'upload',
      name: datasetName,
      source: 'auto-promote',
      rows: [benchmarkCase]
    }, {timeout: 30000, headers: {'X-API-Key': $env.WEBHOOK_API_KEY || ''}});
  } catch(dsErr) {
    return {error: true, message: 'Dataset upload failed: ' + (dsErr.message || String(dsErr)), _status: 500};
  }
  // Tag the trace run as promoted
  await post('/runs/log-batch', {
    run_id: run.info.run_id,
    tags: [{key: 'promoted', value: 'true'}, {key: 'promoted_dataset', value: datasetName}, {key: 'promoted_at', value: new Date().toISOString()}],
    metrics: [{key: 'promoted', value: 1, timestamp: Date.now(), step: 0}]
  });
  return {action: 'promote', trace_id: traceId, dataset: datasetName, case: benchmarkCase, status: 'promoted'};
}

throw new Error('Unknown action: ' + action);

} catch(e) {
  var msg = e.message || String(e);
  if (e.response && e.response.data) msg += ' | ' + JSON.stringify(e.response.data);
  var status = 400;
  if (e.response && e.response.status === 404) status = 404;
  if (msg.indexOf('RESOURCE_DOES_NOT_EXIST') !== -1) status = 404;
  return {error: true, message: msg, action: action || 'unknown', _status: status};
}
